{
  "name": "Sai Lakshya Talkies & Events",
  "description": "A luxury private theatre and celebration booking system with a royal gold and dark maroon theme, featuring dynamic pricing and admin management.",
  "requestFramePermissions": [
    "camera",
    "microphone"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Room {
  id: string;
  name: string;
  image: string;
  price: number;
  basePackage: number;
  maxCapacity: number;
  extraAdultCharge: number;
  extraChildCharge: number;
  description: string;
}

export interface Addon {
  id: string;
  name: string;
  price: number;
  description: string;
}

export interface Booking {
  id: string;
  customerName: string;
  phone: string;
  email: string;
  roomId: string;
  date: string;
  timeSlot: string;
  adults: number;
  children: number;
  addons: string[];
  totalPrice: number;
  status: 'pending' | 'confirmed';
  createdAt: number;
}

export interface AdminCredentials {
  username: string;
  token: string;
}

import React, { useState, useEffect } from 'react';
import { HashRouter as Router, Routes, Route, Link, useLocation } from 'react-router-dom';
import { Menu, X, Crown, Calendar, User, Phone, Mail, Clock, Plus, Trash2, CheckCircle, ChevronRight, LogOut } from 'lucide-react';
import Navbar from './components/Navbar';
import Home from './pages/Home';
import BookingPage from './pages/BookingPage';
import AdminLogin from './pages/AdminLogin';
import AdminDashboard from './pages/AdminDashboard';
import { AdminCredentials } from './types';

function App() {
  const [isAdminLoggedIn, setIsAdminLoggedIn] = useState(false);

  useEffect(() => {
    const savedToken = localStorage.getItem('admin_token');
    if (savedToken) {
      setIsAdminLoggedIn(true);
    }
  }, []);

  const handleAdminLogin = (creds: AdminCredentials) => {
    localStorage.setItem('admin_token', creds.token);
    setIsAdminLoggedIn(true);
  };

  const handleAdminLogout = () => {
    localStorage.removeItem('admin_token');
    setIsAdminLoggedIn(false);
  };

  return (
    <Router>
      <div className="min-h-screen maroon-bg text-white overflow-x-hidden">
        <Navbar isAdmin={isAdminLoggedIn} onLogout={handleAdminLogout} />

        <Routes>
          <Route path="/" element={<Home />} />
          <Route path="/book" element={<BookingPage />} />
          <Route 
            path="/admin" 
            element={isAdminLoggedIn ? <AdminDashboard /> : <AdminLogin onLogin={handleAdminLogin} />} 
          />
        </Routes>

        <footer className="py-12 px-6 border-t border-[#d4af37]/30 bg-black/50 text-center">
          <div className="max-w-7xl mx-auto flex flex-col items-center gap-6">
            <div className="flex items-center gap-2 mb-2">
              <Crown className="text-[#d4af37] w-8 h-8" />
              <span className="font-royal text-2xl gold-gradient font-bold tracking-widest">SAI LAKSHYA</span>
            </div>
            <p className="max-w-2xl text-gray-400 font-light leading-relaxed">
              Experience entertainment like never before. From royal celebrations to intimate couple moments, we provide the perfect sanctuary for your special events.
            </p>
            <div className="flex gap-4 text-[#d4af37]">
              <Link to="/" className="hover:text-white transition-colors">Home</Link>
              <span>•</span>
              <Link to="/book" className="hover:text-white transition-colors">Book Now</Link>
              <span>•</span>
              <Link to="/admin" className="hover:text-white transition-colors">Admin</Link>
            </div>
            <p className="text-gray-500 text-sm mt-4">
              © 2025 SAI LAKSHYA TALKIES & EVENTS. All Rights Reserved.
            </p>
          </div>
        </footer>
      </div>
    </Router>
  );
}

export default App;

import React, { useState } from 'react';
import { Link, useLocation } from 'react-router-dom';
import { Menu, X, Crown, LogOut } from 'lucide-react';

interface NavbarProps {
  isAdmin: boolean;
  onLogout: () => void;
}

const Navbar: React.FC<NavbarProps> = ({ isAdmin, onLogout }) => {
  const [isOpen, setIsOpen] = useState(false);
  const location = useLocation();

  const navLinks = [
    { name: 'HOME', path: '/' },
    { name: 'ROOMS', path: '/#rooms' },
    { name: 'BOOK NOW', path: '/book' },
  ];

  const handleLinkClick = (path: string) => {
    setIsOpen(false);
    if (path.includes('#')) {
      const id = path.split('#')[1];
      const element = document.getElementById(id);
      if (element) {
        element.scrollIntoView({ behavior: 'smooth' });
      }
    }
  };

  return (
    <nav className="fixed w-full z-50 transition-all duration-300 bg-black/80 backdrop-blur-md border-b border-[#d4af37]/20">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex items-center justify-between h-20">
          <Link to="/" className="flex items-center gap-2 group">
            <Crown className="text-[#d4af37] group-hover:rotate-12 transition-transform duration-300" size={32} />
            <div className="flex flex-col">
              <span className="font-royal text-xl md:text-2xl gold-gradient font-black tracking-widest leading-none">SAI LAKSHYA</span>
              <span className="text-[10px] text-gray-400 tracking-[0.3em] font-light">TALKIES & EVENTS</span>
            </div>
          </Link>

          {/* Desktop Menu */}
          <div className="hidden md:flex items-center space-x-8">
            {navLinks.map((link) => (
              <Link
                key={link.name}
                to={link.path}
                onClick={() => handleLinkClick(link.path)}
                className={`font-royal text-sm tracking-widest transition-colors duration-300 hover:text-[#d4af37] ${
                  location.pathname === link.path ? 'text-[#d4af37]' : 'text-white'
                }`}
              >
                {link.name}
              </Link>
            ))}
            {isAdmin && (
              <button 
                onClick={onLogout}
                className="flex items-center gap-2 text-red-400 hover:text-red-300 font-royal text-sm transition-colors"
              >
                <LogOut size={18} />
                LOGOUT
              </button>
            )}
            <Link
              to="/book"
              className="px-6 py-2 bg-gradient-to-r from-[#bf953f] to-[#aa771c] rounded-full font-royal text-sm font-bold tracking-widest text-black hover:scale-105 transition-transform"
            >
              BOOK NOW
            </Link>
          </div>

          {/* Mobile Menu Button */}
          <div className="md:hidden flex items-center">
            <button
              onClick={() => setIsOpen(!isOpen)}
              className="text-[#d4af37] hover:text-white focus:outline-none"
            >
              {isOpen ? <X size={32} /> : <Menu size={32} />}
            </button>
          </div>
        </div>
      </div>

      {/* Mobile Menu */}
      {isOpen && (
        <div className="md:hidden bg-black/95 backdrop-blur-xl border-t border-[#d4af37]/20 animate-fade-in-down">
          <div className="px-4 pt-4 pb-8 space-y-4 text-center">
            {navLinks.map((link) => (
              <Link
                key={link.name}
                to={link.path}
                onClick={() => handleLinkClick(link.path)}
                className="block px-3 py-4 text-xl font-royal text-white hover:text-[#d4af37] transition-colors tracking-widest"
              >
                {link.name}
              </Link>
            ))}
            {isAdmin && (
               <button 
               onClick={() => { onLogout(); setIsOpen(false); }}
               className="block w-full text-center px-3 py-4 text-xl font-royal text-red-400 tracking-widest"
             >
               LOGOUT
             </button>
            )}
            <Link
              to="/book"
              onClick={() => setIsOpen(false)}
              className="block w-full py-4 bg-[#bf953f] text-black font-royal font-bold tracking-widest rounded-lg"
            >
              BOOK NOW
            </Link>
          </div>
        </div>
      )}
    </nav>
  );
};

export default Navbar;

import React, { useState, useEffect } from 'react';
import { ROOMS } from '../constants';
import { ChevronLeft, ChevronRight } from 'lucide-react';

const Carousel: React.FC = () => {
  const [currentIndex, setCurrentIndex] = useState(0);

  useEffect(() => {
    const timer = setInterval(() => {
      setCurrentIndex((prev) => (prev + 1) % ROOMS.length);
    }, 5000);
    return () => clearInterval(timer);
  }, []);

  const next = () => setCurrentIndex((prev) => (prev + 1) % ROOMS.length);
  const prev = () => setCurrentIndex((prev) => (prev - 1 + ROOMS.length) % ROOMS.length);

  return (
    <div className="relative w-full h-[70vh] md:h-[90vh] overflow-hidden">
      {ROOMS.map((room, index) => (
        <div
          key={room.id}
          className={`absolute inset-0 transition-opacity duration-1000 ease-in-out ${
            index === currentIndex ? 'opacity-100' : 'opacity-0'
          }`}
        >
          <div
            className="absolute inset-0 bg-cover bg-center transition-transform duration-[10000ms] ease-linear scale-110"
            style={{ backgroundImage: `url(${room.image})`, transform: index === currentIndex ? 'scale(1)' : 'scale(1.1)' }}
          >
            <div className="absolute inset-0 bg-gradient-to-t from-black via-black/40 to-transparent" />
          </div>
          <div className="absolute inset-0 flex flex-col items-center justify-center text-center px-4">
            <h2 className="font-royal text-4xl md:text-7xl font-black text-white mb-4 drop-shadow-2xl gold-gradient uppercase tracking-widest">
              {room.name}
            </h2>
            <p className="font-royal text-xl md:text-3xl text-[#d4af37] font-bold tracking-widest">
              Starting from ₹{room.price.toLocaleString()}
            </p>
          </div>
        </div>
      ))}

      {/* Controls */}
      <button
        onClick={prev}
        className="absolute left-4 top-1/2 -translate-y-1/2 p-3 rounded-full bg-black/30 text-white hover:bg-[#d4af37]/50 transition-all border border-[#d4af37]/20"
      >
        <ChevronLeft size={32} />
      </button>
      <button
        onClick={next}
        className="absolute right-4 top-1/2 -translate-y-1/2 p-3 rounded-full bg-black/30 text-white hover:bg-[#d4af37]/50 transition-all border border-[#d4af37]/20"
      >
        <ChevronRight size={32} />
      </button>

      {/* Dots */}
      <div className="absolute bottom-10 left-1/2 -translate-x-1/2 flex gap-3">
        {ROOMS.map((_, index) => (
          <button
            key={index}
            onClick={() => setCurrentIndex(index)}
            className={`w-3 h-3 rounded-full transition-all duration-300 ${
              index === currentIndex ? 'bg-[#d4af37] scale-125' : 'bg-gray-500'
            }`}
          />
        ))}
      </div>
    </div>
  );
};

export default Carousel;

import React, { useState, useEffect, useMemo } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
import { User, Phone, Mail, Calendar, Clock, Users, Plus, CheckCircle, Info, Sparkles, ChevronRight } from 'lucide-react';
import { ROOMS, ADDONS, TIME_SLOTS, GOOGLE_FORM_PAYMENT_LINK } from '../constants';
import { Booking } from '../types';

const BookingPage: React.FC = () => {
  const location = useLocation();
  const navigate = useNavigate();
  const preSelectedRoomId = location.state?.roomId || ROOMS[0].id;

  const [formData, setFormData] = useState({
    name: '',
    phone: '',
    email: '',
    roomId: preSelectedRoomId,
    date: '',
    timeSlot: TIME_SLOTS[0],
    adults: 1,
    children: 0,
    selectedAddons: [] as string[]
  });

  const [isSubmitting, setIsSubmitting] = useState(false);
  const [showConfirmation, setShowConfirmation] = useState(false);

  const selectedRoom = useMemo(() => 
    ROOMS.find(r => r.id === formData.roomId) || ROOMS[0], 
    [formData.roomId]
  );

  const totalPrice = useMemo(() => {
    let price = selectedRoom.price;
    const totalMembers = formData.adults + formData.children;

    // Extra members beyond base package
    if (totalMembers > selectedRoom.basePackage) {
      // Logic: Prioritize base package covering adults first, then children
      const extraAdults = Math.max(0, formData.adults - selectedRoom.basePackage);
      const remainingSlots = Math.max(0, selectedRoom.basePackage - formData.adults);
      const extraChildren = Math.max(0, formData.children - remainingSlots);

      price += (extraAdults * selectedRoom.extraAdultCharge);
      price += (extraChildren * selectedRoom.extraChildCharge);
    }

    // Addons
    formData.selectedAddons.forEach(addonId => {
      const addon = ADDONS.find(a => a.id === addonId);
      if (addon) price += addon.price;
    });

    return price;
  }, [formData, selectedRoom]);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const toggleAddon = (addonId: string) => {
    setFormData(prev => ({
      ...prev,
      selectedAddons: prev.selectedAddons.includes(addonId)
        ? prev.selectedAddons.filter(id => id !== addonId)
        : [...prev.selectedAddons, addonId]
    }));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);

    const booking: Booking = {
      id: `BK-${Date.now()}`,
      customerName: formData.name,
      phone: formData.phone,
      email: formData.email,
      roomId: formData.roomId,
      date: formData.date,
      timeSlot: formData.timeSlot,
      adults: formData.adults,
      children: formData.children,
      addons: formData.selectedAddons,
      totalPrice: totalPrice,
      status: 'pending',
      createdAt: Date.now()
    };

    // Save to local storage for admin simulation
    const existingBookings = JSON.parse(localStorage.getItem('bookings') || '[]');
    localStorage.setItem('bookings', JSON.stringify([...existingBookings, booking]));

    // Simulate API delay
    await new Promise(resolve => setTimeout(resolve, 1500));

    setIsSubmitting(false);
    setShowConfirmation(true);
  };

  const handlePaymentRedirect = () => {
    window.open(GOOGLE_FORM_PAYMENT_LINK, '_blank');
    navigate('/');
  };

  if (showConfirmation) {
    return (
      <div className="min-h-screen pt-32 pb-20 px-6 flex items-center justify-center">
        <div className="max-w-xl w-full glass-card p-10 rounded-3xl text-center border-[#d4af37]/50 royal-shadow animate-scale-up">
          <div className="w-24 h-24 bg-[#d4af37] rounded-full flex items-center justify-center mx-auto mb-8 animate-bounce-slow">
            <CheckCircle className="text-black" size={48} />
          </div>
          <h2 className="font-royal text-4xl font-black gold-gradient mb-4">BOOKING RESERVED</h2>
          <p className="text-gray-300 text-lg mb-8 font-light leading-relaxed">
            Your royal experience is just one step away. Please complete the payment on the following screen to confirm your slot.
          </p>
          <div className="bg-black/40 p-6 rounded-xl border border-[#d4af37]/20 mb-10 text-left">
            <div className="flex justify-between mb-2">
              <span className="text-gray-400">Booking ID</span>
              <span className="text-[#d4af37] font-bold">BK-{Date.now().toString().slice(-6)}</span>
            </div>
            <div className="flex justify-between mb-2">
              <span className="text-gray-400">Room</span>
              <span className="text-white">{selectedRoom.name}</span>
            </div>
            <div className="flex justify-between font-bold text-xl mt-4 border-t border-[#d4af37]/20 pt-4">
              <span className="gold-gradient">Total Amount</span>
              <span className="gold-gradient">₹{totalPrice.toLocaleString()}</span>
            </div>
          </div>
          <button
            onClick={handlePaymentRedirect}
            className="w-full py-4 bg-[#d4af37] text-black font-royal font-black text-xl rounded-xl hover:scale-105 transition-all royal-shadow flex items-center justify-center gap-3"
          >
            PROCEED TO PAYMENT
            <ChevronRight />
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen pt-32 pb-20 px-4 md:px-6">
      <div className="max-w-7xl mx-auto">
        <div className="text-center mb-12">
          <h1 className="font-royal text-5xl font-black gold-gradient uppercase tracking-widest mb-4">Royal Booking</h1>
          <p className="text-gray-400 font-light text-lg">Reserve your private sanctuary in just a few clicks.</p>
        </div>

        <form onSubmit={handleSubmit} className="grid lg:grid-cols-3 gap-8">
          {/* Left: User Details */}
          <div className="lg:col-span-2 space-y-8">
            <div className="glass-card p-8 rounded-2xl border-[#d4af37]/20">
              <h3 className="font-royal text-2xl font-bold mb-6 flex items-center gap-3">
                <User className="text-[#d4af37]" />
                PERSONAL DETAILS
              </h3>
              <div className="grid md:grid-cols-2 gap-6">
                <div>
                  <label className="block text-gray-400 text-xs tracking-widest uppercase mb-2">Full Name</label>
                  <div className="relative">
                    <User className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500" size={18} />
                    <input 
                      required
                      type="text" 
                      name="name"
                      value={formData.name}
                      onChange={handleInputChange}
                      placeholder="Enter your name"
                      className="w-full pl-10 pr-4 py-3 bg-black/40 border border-white/10 rounded-lg focus:border-[#d4af37] outline-none transition-colors"
                    />
                  </div>
                </div>
                <div>
                  <label className="block text-gray-400 text-xs tracking-widest uppercase mb-2">Phone Number</label>
                  <div className="relative">
                    <Phone className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500" size={18} />
                    <input 
                      required
                      type="tel" 
                      name="phone"
                      value={formData.phone}
                      onChange={handleInputChange}
                      placeholder="10-digit number"
                      className="w-full pl-10 pr-4 py-3 bg-black/40 border border-white/10 rounded-lg focus:border-[#d4af37] outline-none transition-colors"
                    />
                  </div>
                </div>
                <div className="md:col-span-2">
                  <label className="block text-gray-400 text-xs tracking-widest uppercase mb-2">Email Address</label>
                  <div className="relative">
                    <Mail className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500" size={18} />
                    <input 
                      required
                      type="email" 
                      name="email"
                      value={formData.email}
                      onChange={handleInputChange}
                      placeholder="you@example.com"
                      className="w-full pl-10 pr-4 py-3 bg-black/40 border border-white/10 rounded-lg focus:border-[#d4af37] outline-none transition-colors"
                    />
                  </div>
                </div>
              </div>
            </div>

            <div className="glass-card p-8 rounded-2xl border-[#d4af37]/20">
              <h3 className="font-royal text-2xl font-bold mb-6 flex items-center gap-3">
                <Calendar className="text-[#d4af37]" />
                SESSION DETAILS
              </h3>
              <div className="grid md:grid-cols-2 gap-6">
                <div>
                  <label className="block text-gray-400 text-xs tracking-widest uppercase mb-2">Select Room</label>
                  <select 
                    name="roomId"
                    value={formData.roomId}
                    onChange={handleInputChange}
                    className="w-full px-4 py-3 bg-black/40 border border-white/10 rounded-lg focus:border-[#d4af37] outline-none transition-colors appearance-none"
                  >
                    {ROOMS.map(room => (
                      <option key={room.id} value={room.id} className="bg-[#1a0000]">{room.name}</option>
                    ))}
                  </select>
                </div>
                <div>
                  <label className="block text-gray-400 text-xs tracking-widest uppercase mb-2">Date</label>
                  <div className="relative">
                    <Calendar className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500" size={18} />
                    <input 
                      required
                      type="date" 
                      name="date"
                      min={new Date().toISOString().split('T')[0]}
                      value={formData.date}
                      onChange={handleInputChange}
                      className="w-full pl-10 pr-4 py-3 bg-black/40 border border-white/10 rounded-lg focus:border-[#d4af37] outline-none transition-colors"
                    />
                  </div>
                </div>
                <div>
                  <label className="block text-gray-400 text-xs tracking-widest uppercase mb-2">Time Slot (3 Hours)</label>
                  <div className="relative">
                    <Clock className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500" size={18} />
                    <select 
                      name="timeSlot"
                      value={formData.timeSlot}
                      onChange={handleInputChange}
                      className="w-full pl-10 pr-4 py-3 bg-black/40 border border-white/10 rounded-lg focus:border-[#d4af37] outline-none transition-colors appearance-none"
                    >
                      {TIME_SLOTS.map(slot => (
                        <option key={slot} value={slot} className="bg-[#1a0000]">{slot}</option>
                      ))}
                    </select>
                  </div>
                </div>
                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <label className="block text-gray-400 text-xs tracking-widest uppercase mb-2">Adults</label>
                    <input 
                      type="number" 
                      min="1"
                      max={selectedRoom.maxCapacity}
                      name="adults"
                      value={formData.adults}
                      onChange={handleInputChange}
                      className="w-full px-4 py-3 bg-black/40 border border-white/10 rounded-lg focus:border-[#d4af37] outline-none transition-colors"
                    />
                  </div>
                  <div>
                    <label className="block text-gray-400 text-xs tracking-widest uppercase mb-2">Children</label>
                    <input 
                      type="number" 
                      min="0"
                      name="children"
                      value={formData.children}
                      onChange={handleInputChange}
                      className="w-full px-4 py-3 bg-black/40 border border-white/10 rounded-lg focus:border-[#d4af37] outline-none transition-colors"
                    />
                  </div>
                </div>
              </div>
            </div>

            <div className="glass-card p-8 rounded-2xl border-[#d4af37]/20">
              <h3 className="font-royal text-2xl font-bold mb-6 flex items-center gap-3">
                <Sparkles className="text-[#d4af37]" />
                ROYAL ADD-ONS
              </h3>
              <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-4">
                {ADDONS.map(addon => (
                  <button
                    key={addon.id}
                    type="button"
                    onClick={() => toggleAddon(addon.id)}
                    className={`p-4 rounded-xl border-2 transition-all text-left flex flex-col justify-between h-32 ${
                      formData.selectedAddons.includes(addon.id)
                        ? 'bg-[#d4af37]/10 border-[#d4af37]'
                        : 'bg-black/40 border-white/5 hover:border-white/20'
                    }`}
                  >
                    <div>
                      <span className="block font-bold text-sm mb-1">{addon.name}</span>
                      <span className="block text-gray-500 text-xs leading-tight">{addon.description}</span>
                    </div>
                    <span className="block text-[#d4af37] font-royal font-bold">₹{addon.price}</span>
                  </button>
                ))}
              </div>
            </div>
          </div>

          {/* Right: Booking Summary */}
          <div className="lg:col-span-1">
            <div className="sticky top-24 space-y-6">
              <div className="glass-card p-8 rounded-2xl border-[#d4af37]/50 border-t-4 royal-shadow overflow-hidden relative">
                <div className="absolute top-0 right-0 w-32 h-32 bg-[#d4af37] opacity-5 -translate-y-1/2 translate-x-1/2 rounded-full blur-3xl"></div>

                <h3 className="font-royal text-2xl font-black mb-6 gold-gradient uppercase text-center">Summary</h3>

                <div className="space-y-4 mb-8">
                  <div className="flex justify-between items-center text-sm">
                    <span className="text-gray-400">Room Base Price</span>
