const ParallaxImage: React.FC<{ src: string; alt: string }> = ({ src, alt }) => {
  const imageRef = useRef<HTMLImageElement>(null);

  useEffect(() => {
    const handleScroll = () => {
      if (!imageRef.current) return;

      const rect = imageRef.current.getBoundingClientRect();
      const windowHeight = window.innerHeight;

      // Check if the element is visible in the viewport
      if (rect.top < windowHeight && rect.bottom > 0) {
        // Calculate the relative scroll progress through the viewport (0 to 1)
        const progress = (windowHeight - rect.top) / (windowHeight + rect.height);
        // Move the image slightly (range: -20px to 20px)
        const translateY = (progress - 0.5) * 40; 
        imageRef.current.style.transform = `scale(1.1) translateY(${translateY}px)`;
      }
    };

    window.addEventListener('scroll', handleScroll, { passive: true });
    handleScroll(); // Initial call

    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  return (
    <img 
      ref={imageRef}
      src={src} 
      alt={alt} 
      className="w-full h-full object-cover transition-transform duration-100 ease-out will-change-transform scale-110"
    />
  );
};

