import React, { useState, useEffect, useMemo } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
import { User, Phone, Mail, Calendar, Clock, Users, Plus, CheckCircle, Info, Sparkles, ChevronRight } from 'lucide-react';
import { ROOMS, ADDONS, TIME_SLOTS, GOOGLE_FORM_PAYMENT_LINK } from '../constants';
import { Booking } from '../types';
import { useToast } from '../App';

const BookingPage: React.FC = () => {
  const location = useLocation();
  const navigate = useNavigate();
  const { showToast } = useToast();
  const preSelectedRoomId = location.state?.roomId || ROOMS[0].id;

  const [formData, setFormData] = useState({
    name: '',
    phone: '',
    email: '',
    roomId: preSelectedRoomId,
    date: '',
    timeSlot: TIME_SLOTS[0],
    adults: 1,
    children: 0,
    selectedAddons: [] as string[]
  });

  const [isSubmitting, setIsSubmitting] = useState(false);
  const [showConfirmation, setShowConfirmation] = useState(false);

  const selectedRoom = useMemo(() => 
    ROOMS.find(r => r.id === formData.roomId) || ROOMS[0], 
    [formData.roomId]
  );

  const totalPrice = useMemo(() => {
    let price = selectedRoom.price;
    const totalMembers = formData.adults + formData.children;

    if (totalMembers > selectedRoom.basePackage) {
      const extraAdults = Math.max(0, formData.adults - selectedRoom.basePackage);
      const remainingSlots = Math.max(0, selectedRoom.basePackage - formData.adults);
      const extraChildren = Math.max(0, formData.children - remainingSlots);

      price += (extraAdults * selectedRoom.extraAdultCharge);
      price += (extraChildren * selectedRoom.extraChildCharge);
    }

    formData.selectedAddons.forEach(addonId => {
      const addon = ADDONS.find(a => a.id === addonId);
      if (addon) price += addon.price;
    });

    return price;
  }, [formData, selectedRoom]);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const toggleAddon = (addonId: string) => {
    setFormData(prev => ({
      ...prev,
      selectedAddons: prev.selectedAddons.includes(addonId)
        ? prev.selectedAddons.filter(id => id !== addonId)
        : [...prev.selectedAddons, addonId]
    }));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);

    const booking: Booking = {
      id: `BK-${Date.now()}`,
      customerName: formData.name,
      phone: formData.phone,
      email: formData.email,
      roomId: formData.roomId,
      date: formData.date,
      timeSlot: formData.timeSlot,
      adults: formData.adults,
      children: formData.children,
      addons: formData.selectedAddons,
      totalPrice: totalPrice,
      status: 'pending',
      createdAt: Date.now()
    };

    const existingBookings = JSON.parse(localStorage.getItem('bookings') || '[]');
    localStorage.setItem('bookings', JSON.stringify([...existingBookings, booking]));

    await new Promise(resolve => setTimeout(resolve, 1500));

    setIsSubmitting(false);
    setShowConfirmation(true);
    showToast('Booking Initialized', 'Your royal session has been prepared. Please complete payment.', 'success');
  };

  const handlePaymentRedirect = () => {
    showToast('Redirecting', 'Sending you to our secure payment gateway...', 'info');
    setTimeout(() => {
      window.open(GOOGLE_FORM_PAYMENT_LINK, '_blank');
      navigate('/');
    }, 800);
  };

  if (showConfirmation) {
    return (
      <div className="min-h-screen pt-32 pb-20 px-6 flex items-center justify-center">
        <div className="max-w-xl w-full glass-card p-10 rounded-3xl text-center border-[#d4af37]/50 royal-shadow animate-scale-up">
          <div className="w-24 h-24 bg-[#d4af37] rounded-full flex items-center justify-center mx-auto mb-8 animate-bounce-slow">
            <CheckCircle className="text-black" size={48} />
          </div>
          <h2 className="font-royal text-4xl font-black gold-gradient mb-4">BOOKING RESERVED</h2>
          <p className="text-gray-300 text-lg mb-8 font-light leading-relaxed">
            Your royal experience is just one step away. Please complete the payment on the following screen to confirm your slot.
          </p>
          <div className="bg-black/40 p-6 rounded-xl border border-[#d4af37]/20 mb-10 text-left">
            <div className="flex justify-between mb-2">
              <span className="text-gray-400">Booking ID</span>
              <span className="text-[#d4af37] font-bold">BK-{Date.now().toString().slice(-6)}</span>
            </div>
            <div className="flex justify-between mb-2">
              <span className="text-gray-400">Room</span>
              <span className="text-white">{selectedRoom.name}</span>
            </div>
            <div className="flex justify-between font-bold text-xl mt-4 border-t border-[#d4af37]/20 pt-4">
              <span className="gold-gradient">Total Amount</span>
              <span className="gold-gradient">₹{totalPrice.toLocaleString()}</span>
            </div>
          </div>
          <button
            onClick={handlePaymentRedirect}
            className="w-full py-4 bg-[#d4af37] text-black font-royal font-black text-xl rounded-xl hover:scale-105 transition-all royal-shadow flex items-center justify-center gap-3"
          >
            PROCEED TO PAYMENT
            <ChevronRight />
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen pt-32 pb-20 px-4 md:px-6">
      <div className="max-w-7xl mx-auto">
