                  )}

                  {formData.selectedAddons.length > 0 && (
                    <div className="pt-4 border-t border-white/5 space-y-2">
                      <span className="text-xs font-royal text-[#d4af37] tracking-widest block uppercase">Selected Add-ons</span>
