                      })}
                    </div>
                  )}
                </div>

                <div className="pt-6 border-t border-[#d4af37]/30 flex justify-between items-center mb-8">
                  <span className="font-royal text-xl font-bold">TOTAL PRICE</span>
                  <span className="font-royal text-3xl font-black gold-gradient">₹{totalPrice.toLocaleString()}</span>
                </div>

                <button
                  type="submit"
                  disabled={isSubmitting}
                  className={`w-full py-4 bg-gradient-to-r from-[#bf953f] to-[#aa771c] text-black font-royal font-black text-lg tracking-widest rounded-xl transition-all duration-300 transform ${
                    isSubmitting ? 'opacity-70 cursor-not-allowed scale-95' : 'hover:scale-105 active:scale-95 royal-shadow'
                  }`}
                >
