const ParallaxImage: React.FC<{ src: string; alt: string }> = ({ src, alt }) => {
  const imageRef = useRef<HTMLImageElement>(null);

  useEffect(() => {
    let ticking = false;

    const updatePosition = () => {
      if (!imageRef.current) return;

      const rect = imageRef.current.getBoundingClientRect();
      const windowHeight = window.innerHeight;

      // Check if the element is visible in the viewport
      if (rect.top < windowHeight && rect.bottom > 0) {
        // Calculate the relative scroll progress through the viewport (0 to 1)
        const progress = (windowHeight - rect.top) / (windowHeight + rect.height);
        // Move the image slightly (range: -30px to 30px for a bit more noticeable depth)
        const translateY = (progress - 0.5) * 60; 
        // Use translate3d to trigger hardware acceleration
        imageRef.current.style.transform = `scale(1.2) translate3d(0, ${translateY}px, 0)`;
      }
      ticking = false;
    };

    const handleScroll = () => {
      if (!ticking) {
        window.requestAnimationFrame(updatePosition);
        ticking = true;
      }
    };

    window.addEventListener('scroll', handleScroll, { passive: true });
    // Initial call to set position
    updatePosition();

    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  return (
    <div className="w-full h-full overflow-hidden relative">
      <img 
        ref={imageRef}
        src={src} 
        alt={alt} 
        className="w-full h-full object-cover will-change-transform"
        style={{ transform: 'scale(1.2)' }}
      />
    </div>
  );
};

