  const [activeTab, setActiveTab] = useState<'bookings' | 'analytics' | 'rooms'>('bookings');
  const [viewMode, setViewMode] = useState<'list' | 'calendar'>('list');
  const [searchTerm, setSearchTerm] = useState('');
  const [currentMonth, setCurrentMonth] = useState(new Date());
  const [selectedDate, setSelectedDate] = useState<string | null>(null);

  useEffect(() => {
    loadBookings();
  }, []);

  const loadBookings = () => {
    const data = JSON.parse(localStorage.getItem('bookings') || '[]');
    setBookings(data.sort((a: Booking, b: Booking) => b.createdAt - a.createdAt));
  };

  const handleDelete = (id: string) => {
    if (window.confirm('Delete this booking permanently?')) {
      const updated = bookings.filter(b => b.id !== id);
      localStorage.setItem('bookings', JSON.stringify(updated));
      setBookings(updated);
    }
  };

  const handleConfirm = (id: string) => {
    const updated = bookings.map(b => 
      b.id === id ? { ...b, status: 'confirmed' as const } : b
    );
    localStorage.setItem('bookings', JSON.stringify(updated));
    setBookings(updated);
  };

  const filteredBookings = useMemo(() => {
    let result = bookings;
    if (searchTerm) {
      result = result.filter(b => 
        b.customerName.toLowerCase().includes(searchTerm.toLowerCase()) ||
        b.id.toLowerCase().includes(searchTerm.toLowerCase()) ||
        b.phone.includes(searchTerm)
      );
    }
    if (selectedDate && viewMode === 'calendar') {
      result = result.filter(b => b.date === selectedDate);
    }
    return result;
  }, [bookings, searchTerm, selectedDate, viewMode]);

  // Calendar Logic
  const daysInMonth = (year: number, month: number) => new Date(year, month + 1, 0).getDate();
  const firstDayOfMonth = (year: number, month: number) => new Date(year, month, 1).getDay();

  const calendarDays = useMemo(() => {
    const year = currentMonth.getFullYear();
    const month = currentMonth.getMonth();
    const totalDays = daysInMonth(year, month);
    const offset = firstDayOfMonth(year, month);
    const days = [];

    for (let i = 0; i < offset; i++) days.push(null);
    for (let i = 1; i <= totalDays; i++) {
      const dateStr = `${year}-${String(month + 1).padStart(2, '0')}-${String(i).padStart(2, '0')}`;
      const dayBookings = bookings.filter(b => b.date === dateStr);
      days.push({ day: i, date: dateStr, bookings: dayBookings });
    }
    return days;
