const ParallaxImage: React.FC<{ src: string; alt: string }> = ({ src, alt }) => {
  const imageRef = useRef<HTMLImageElement>(null);

  useEffect(() => {
    let ticking = false;

    const updatePosition = () => {
      if (!imageRef.current) return;

      const rect = imageRef.current.getBoundingClientRect();
      const windowHeight = window.innerHeight;

      // Check if the element is visible in the viewport
      if (rect.top < windowHeight && rect.bottom > 0) {
        // Calculate the center of the viewport
        const viewportCenter = windowHeight / 2;
        // Calculate the center of the element relative to the viewport
        const elementCenter = rect.top + rect.height / 2;
        // Calculate the distance from the center of the viewport (-0.5 to 0.5)
        const distanceFromCenter = (elementCenter - viewportCenter) / windowHeight;

        // Intensity of the parallax effect (higher value = more movement)
        const parallaxFactor = 50; 
        const translateY = distanceFromCenter * parallaxFactor;

        // Use translate3d for GPU acceleration and scale to prevent edges showing
        // scale(1.15) provides enough padding for the movement
        imageRef.current.style.transform = `scale(1.15) translate3d(0, ${translateY}px, 0)`;
      }
      ticking = false;
    };

    const onScroll = () => {
      if (!ticking) {
        window.requestAnimationFrame(updatePosition);
        ticking = true;
      }
    };

    window.addEventListener('scroll', onScroll, { passive: true });
    // Run once on mount to set initial position
    updatePosition();

    return () => window.removeEventListener('scroll', onScroll);
  }, []);

  return (
    <div className="w-full h-full overflow-hidden relative bg-black">
      <img 
        ref={imageRef}
        src={src} 
        alt={alt} 
        className="w-full h-full object-cover will-change-transform"
        style={{ transform: 'scale(1.15)' }}
      />
    </div>
  );
};

