                              <span className="text-[10px] text-gray-400 uppercase tracking-widest">
                                {b.paymentOption === 'full' ? 'Full Payment' : `Advance (Total: ₹${b.totalPrice.toLocaleString()})`}
                              </span>
                            </div>
                          </td>
                          <td className="px-6 py-4">
